# 分离数据
episodes = np.array([x[0] for x in data])
rewards = np.array([x[1] for x in data])

# 使用 Pandas 计算移动平均 (窗口大小为 50)
window_size = 50
s_rewards = pd.Series(rewards)
moving_avg = s_rewards.rolling(window=window_size, min_periods=1).mean()

# 创建画布
fig, ax = plt.subplots(figsize=(12, 6), dpi=100)

# 1. 绘制原始奖励（浅色，作为背景noise）
ax.plot(episodes, rewards, color='#1f77b4', alpha=0.2, linewidth=0.5, label='Raw Episode Reward')

# 2. 绘制移动平均线（深色，加粗，展示主要趋势）
ax.plot(episodes, moving_avg, color='#1f77b4', alpha=1.0, linewidth=2, label=f'Moving Average (w={window_size})')

# 3. 标注关键节点
# 寻找第一次突破 -15 分的 Episode
try:
    idx_15 = np.where(moving_avg > -15)[0][0]
    ax.scatter(episodes[idx_15], moving_avg[idx_15], color='green', s=50, zorder=5)
    ax.annotate(f'Start Learning\n(Ep {episodes[idx_15]})',
                xy=(episodes[idx_15], moving_avg[idx_15]),
                xytext=(episodes[idx_15]-150, moving_avg[idx_15]+3),
                arrowprops=dict(facecolor='black', shrink=0.05, width=1, headwidth=5))
except: pass

# 寻找第一次突破 0 分的 Episode
try:
    idx_0 = np.where(moving_avg > 0)[0][0]
    ax.scatter(episodes[idx_0], moving_avg[idx_0], color='red', s=50, zorder=5)
    ax.annotate(f'Break Even (0 pts)\n(Ep {episodes[idx_0]})',
                xy=(episodes[idx_0], moving_avg[idx_0]),
                xytext=(episodes[idx_0]-200, moving_avg[idx_0]-5),
                arrowprops=dict(facecolor='black', shrink=0.05, width=1, headwidth=5))
except: pass


# 4. 图表装饰
ax.set_title('DQN Agent Performance on ALE/Pong-v5', fontsize=14, fontweight='bold')
ax.set_xlabel('Training Episode', fontsize=12)
ax.set_ylabel('Total Reward', fontsize=12)

# 设置坐标轴范围和网格
ax.set_ylim(-21.5, 22)
ax.grid(True, linestyle=':', alpha=0.6)

# 高亮 0 分水平线
ax.axhline(y=0, color='black', linestyle='-', linewidth=1.5, alpha=0.7)
ax.axhline(y=-21, color='grey', linestyle='--', linewidth=1, alpha=0.5) # 最低分线

ax.legend(loc='upper left')

plt.tight_layout()
plt.show()